var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"괘, 괜찮아?! 컵이 깨졌잖아!","JPN":"だ、大丈夫！？　コップが割れてるじゃない！","ENG":"A-are you okay? The cup broke!","TWN":"沒事吧？杯子碎了！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"다치진 않았어?","JPN":"怪我はしてない？","ENG":"Did you hurt yourself?","TWN":"妳沒受傷吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"......이건!","JPN":"……これは！","ENG":"Could this be...","TWN":"……這是！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"컵이 저절로 깨지다니, 역시 이건 불길한 신탁인가?","JPN":"コップが自然に割れるなんて、何か不吉な神託でしょうか？","ENG":"The cup just shattered on its own. Is this some kind of ominous omen?","TWN":"杯子竟然會自己碎掉了，這果然是什麼不吉利的徵兆嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"대흉 같은 게 밀려올 징조인 건가?!","JPN":"悪運が一気に押し寄せる兆候なのでしょうか！？","ENG":"A sign of something terrible to come?!","TWN":"比如說凶邪之物即將降臨的徵兆嗎？！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"무슨 바보 같은 말이죠? 당연히 이 컵이 불량품이란 뜻이죠.","JPN":"なにバカげたこと言ってるの？　このコップが不良品だってことでしょ。","ENG":"Don't be ridiculous. It just means the cup was faulty.","TWN":"妳在說什麼傻話？ 當然是因為這個杯子是瑕疵品啊。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"컵이 깨졌다고 불행이 닥치다니 그런 미신 같은 소리가 어디 있나요?","JPN":"コップが割れたから不幸が起きるだなんて、そんな迷信じみたことをよくもまあ言えたものね。","ENG":"You thought this was some kind of an omen? How superstitious of you.","TWN":"因為杯子碎了，所以不幸就會降臨，哪有這種迷信的事情啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"한─심하네요, 레나 양.","JPN":"情けないったらありゃしない。","ENG":"That’s pretty pathetic, Lena.","TWN":"真不敢相信妳會有這種愚蠢想法，蕾娜小姐。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"사이비 종교 같은 곳에 끌려가지 않도록 주의하셔야겠어요.","JPN":"えせ宗教みたいなところに連れて行かれないように、よーく気をつけてよね。","ENG":"You’d better be careful you don’t end up in some kind of cult.","TWN":"妳要小心不要被騙進那種邪教組織喔。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"그럼 전 이만.","JPN":"じゃあ、私はこれで。","ENG":"Bye now.","TWN":"那我就先走了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"야! 너! 내가! 어?! 그러니까, 와 진짜! 거기 서! 야!","JPN":"ねえ！　あんた！　私が！　はあ！？　ねえ、ホント！　待ちなさい！　待ちなさいってば！","ENG":"Hey! You! Come on! Seriously?! You've got to be kidding me! Stop right there! Hey!","TWN":"喂！妳這傢伙！妳在說什麼啦？真是的！給我站住！喂！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서, 우린 지금 어디로 가고 있는 거지?","JPN":"それで、私たちは今どこに向かってるの？","ENG":"So, where are we headed?","TWN":"所以，我們現在要去哪裡啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"굉장히 철학적인 질문이네요.","JPN":"とても哲学的な質問ですね。","ENG":"That’s a very philosophical question.","TWN":"嗯，這是個哲學的問題呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 현실적인 의미로 대답하자면, 음.......","JPN":"ですが、現実的な意味で答えると、そうですねえ……","ENG":"But to give you a more literal answer, hmm...","TWN":"但如果按照實際情況來回答妳的話，嗯……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이면세계의 차원 단층 사이를 아슬아슬하게 날고 있다고 할 수 있겠네요.","JPN":"カウンターサイドの次元断層の間をスレスレに飛んでいると言えますかね。","ENG":"I'd say we’re flying precariously between the dimensional strata of the Counterside.","TWN":"可以說，我們正在異界的次元斷層間驚險地飛行。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......온몸에 벌레가 기어다니는 것 같아.","JPN":"……全身に虫が這っているみたい。","ENG":"I feel like there are bugs crawling all over my body.","TWN":"……我全身好像有蟲子在爬一樣。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 불길한 느낌은 대체 뭐야?","JPN":"この不吉な感じは一体何なの？","ENG":"What’s this ominous feeling?","TWN":"這種不祥的感覺，到底是什麼啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"기분 탓입니다...... 라고 말하고 싶지만 확실히 불길한 곳이군요.","JPN":"気のせいです……と言いたいところですが、確かに不吉な場所ですね。","ENG":"I wish I could say it's all in your head... but you're right. This place gives me the creeps too.","TWN":"是妳的錯覺……雖然我很想跟妳這樣說，但這裡的確是個不太吉利的地方呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"여긴 분명 관리국에서 다이브 금지구역으로 지정되어 있는 곳일 텐데......","JPN":"ここは確か、管理局からダイブ禁止区域として指定されているところだと思いますが……","ENG":"I’m pretty sure the Administration banned diving in this area...","TWN":"這裡肯定是管理局指定為禁止躍入的區域。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님은 대체 어떻게 이런 곳을 알고 있는 걸까요?","JPN":"師匠はどうしてこんな所を知っているんでしょうか。","ENG":"How does the Master even know about this sort of place?","TWN":"師父您是怎麼知道這個地方的呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"다들 준비해. 곧 도착한다.","JPN":"みんな準備しろ。　もうすぐ到着だ。","ENG":"Get ready everyone. We’re almost there.","TWN":"所有人做好準備，馬上就要到了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"괜찮을까요? 이미 관리국 표준 좌표에서 한참 벗어났는데요.......","JPN":"大丈夫でしょうか？　すでに管理局の標準座標からかなり離れているのですが……","ENG":"Are you sure this is okay? We’re way off the Administration-sanctioned charts.","TWN":"真的沒關係嗎？我們已經脫離管理局的標準座標很遠了。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"더구나 금지구역에 들어온 게 알려지면 중징계라고요.","JPN":"禁止区域に入ったことがバレたら、重い懲戒処分を受けますよ。","ENG":"Worse yet, we're in a banned area. We could get in serious trouble if they find out.","TWN":"再說，如果我們進入禁區的消息一旦傳開，會受到很重的處分的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어쩌면 태스크포스 라이선스가 박탈될지도 몰라요.","JPN":"ひょっとすると、タスクフォースカンパニーのライセンスも剥奪されるかもしれません。","ENG":"They might even revoke our TASKFORCE license.","TWN":"說不定連特遣勢力執照都會被吊銷。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"설마 수습기간도 끝나기 전에 실업자가 되는 건 아니겠죠? 하아.......","JPN":"まさか試用期間が終わる前に職を失うことにはなりませんよね？　はあ……","ENG":"I’m not going to end up unemployed even before my probationary period is over, am I? Aw...","TWN":"該不會在試用期間結束前，我就先失業了吧？唉……"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마라.","JPN":"案ずるな。","ENG":"Don't worry.","TWN":"不要擔心。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우린 금지구역 바깥에서 임시좌표를 통해 접근한 거니까 외부에서 알아차릴 일은 없어.","JPN":"私たちは禁止区域の外側から臨時座標を使って来たんだから、外部の人間に気づかれることはない。","ENG":"We approached through transient coordinates from outside the banned zone. There’s no way they’ll find out.","TWN":"我們是在禁區外，透過臨時座標接近這裡的，所以外界不會注意到我們。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그리고 금지구역이라고 해서 딱히 뭔가 다른 것도 아니야.","JPN":"それに禁止区域だからといって、何かが変わるわけでもない。","ENG":"Besides, there’s nothing special about banned zones.","TWN":"而且，這裡雖然叫作禁區，但其實也沒有什麼特別的。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"가끔이긴 하지만 도굴꾼이나 해적들도 심심찮게 들어오는 곳이다.","JPN":"たまにだが盗掘者や海賊が出入りするようなところだ。","ENG":"Looters and pirates come here sometimes too, though not often.","TWN":"就只是無聊的盜墓者和海盜偶爾會來的地方。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"아, 알겠습니다. 다이브 아웃!","JPN":"りょ、了解しました。ダイブアウト！","ENG":"U-understood. Dive out!","TWN":"好吧，我知道了，躍出！"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 소대장. 그 이상한 남자가 나래를 데려간 곳이 정말 여기야?","JPN":"小隊長。あの妙な男がナルミを連れ込んだのは、本当にここなの？","ENG":"Hey, Commander. Did that weirdo really bring Narae here?","TWN":"喂，小隊長，那個奇怪的男人帶娜拉去的地方，真的是這裡嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"왜? 잘못 찾아왔을까 봐 걱정이라도 되나, 신입?","JPN":"どうした新人？　場所を間違えてないか心配なのか？","ENG":"Why? You worried we might have the wrong address, rookie?","TWN":"怎麼了？妳在擔心我們來錯地方了嗎？新人？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 건 아니지만....... 대체 왜 이런 곳에서 보자고 한 거지?","JPN":"そうじゃないけど……一体どうしてこんなところにしたんだろう。","ENG":"It’s not that... I’m just curious why he’d ask to meet in a place like this.","TWN":"我不是這個意思……但到底為什麼說要在這種地方見啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 맹세를 저버렸다는 건 또 뭐야?","JPN":"あと、誓いを破ったというのはどういう意味？","ENG":"And what did he mean by broken promises?","TWN":"還有，打破誓言的地方又是什麼意思？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 남자와 무슨 원한이라도 있었던 거야?","JPN":"あの男と何か因縁でもあるの？","ENG":"Does he have a grudge against you or something?","TWN":"是和那個男人有什麼恩怨嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"......개인적인 일이다. 네가 신경 쓸 문제는 아냐.","JPN":"……個人的なことだ。お前が気にする問題ではない。","ENG":"It’s personal. It’s none of your concern.","TWN":"……這是我個人的事情，不是妳該管的問題。"},"stage":{"bg":"PROLOGUE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그보다, 같이 오긴 했지만 우린 엄연히 목적이 다르다. 알고 있겠지?","JPN":"それより、一緒に来たのはいいが、我々の目的は異なる。わかっているな？","ENG":"More importantly, you and I have clearly different objectives here. Remember?","TWN":"我們雖然是一起來的，但各自的目的完全不同，懂嗎？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"난 그 녀석에게, 넌 리플레이서 비숍에게. 각자 볼일이 있지.","JPN":"私はあいつに、お前はリプレイサー・ビショップに、それぞれ用がある。","ENG":"My business is with him. Your is with the Replacer Bishop. We each have our own thing to settle.","TWN":"我是來找那個傢伙，妳是來找克隆·大主教，我們各自處理各自的事。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"친구를 구하고 싶으면 쓸데없는 데 신경 쓰지 말고 거기에 집중하도록.","JPN":"友達を救いたいなら、余計なことは気にせずそこに集中するように。","ENG":"If you want to save your friend, focus on that instead of poking your nose around.","TWN":"妳想找朋友的話，就不要在無關緊要的地方耗費精力，專注在妳自己的事情上。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......알겠어.","JPN":"……わかった。","ENG":"Got it...","TWN":"……知道了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"현재 주변 상황 확인 중. 특별한 것은 보이지 않습니다.","JPN":"現在、周辺状況を確認中。特に変わったものは見当たりません。","ENG":"Scanning the area for any anomalies... Nothing significant to report.","TWN":"現在正在確認周圍的情況，沒有異常。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"침식파 상태 안정, 양자 레벨 정상.","JPN":"侵食波状態は安定しており、量子レベルも正常。","ENG":"Corruption ray stable. Quantum level stable.","TWN":"侵蝕波狀態穩定，量子等級正常。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"너무 조용한데요.","JPN":"異様に静かですね。","ENG":"It’s too quiet.","TWN":"真是安靜呢。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이건 마치....... 죽어 버린 세계 같네요.","JPN":"これではまるで……死後の世界みたいですね。","ENG":"It’s as if... this world has died.","TWN":"但這樣……簡直就像個已經死去的世界。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"대체 여기에서 과거에 무슨 일이 있었던 걸까요? 스승님.","JPN":"一体ここで過去に何かあったんですか？　師匠。","ENG":"I wonder what happened here? Master?","TWN":"這裡以前到底發生了什麼事，師父？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 자식은 어디에 있는 거지? 빨리 찾아야.......","JPN":"あいつはどこにいるんだ？　早く探さないと……","ENG":"Where the hell is that bastard? We have to find him quickly...","TWN":"那傢伙在哪裡？得快點找到他……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"차원계면 진동 관측! 고준위 침식파 반응!","JPN":"次元界面の振動を観測！　高レベルの侵食波反応！","ENG":"Vibrations detected on the dimension surface! High level corruption ray response detected!","TWN":"觀測到次元界面振動！高等侵蝕波反應！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"위상 공간으로부터 침식체들이 현 차원으로 진입합니다! 특이체 다수!","JPN":"位相空間の侵食体が現在の次元に進入してきます！　特異体、多数！","ENG":"C.O.'s entering the current dimension through phased space! Multiple unique types detected!","TWN":"侵蝕體從相位空間進入了現次元！大多是特異體！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"환영인사치고는 과격하군.","JPN":"歓迎のあいさつにしてはずいぶん過激だな。","ENG":"Seems pretty excessive for a welcome party.","TWN":"這份歡迎我們的大禮也太盛大了吧。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"함교, 강하하겠다. 격납고 램프 도어 개방을 요청한다.","JPN":"ブリッジ降下せよ。格納庫のランプドア開放を要請する。","ENG":"Bridge, prepare for the drop. Requesting insertion via the ramp door.","TWN":"艦橋，準備降落，請求打開機庫的艙門。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"가자, 펜릴 소대. 전투다.","JPN":"フェンリル小隊、いくぞ！　戦闘開始だ。","ENG":"Let’s go, Fenrir Squad. Prepare to engage.","TWN":"上吧，芬里爾小隊，戰鬥了。"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_NORMAL_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};